#ifndef FLT_MAX
#define FLT_MAX 3.40282347e+38F
#endif

__attribute__((always_inline))
float euclid_dist_2_cl(const float *pt1,
                       const float *pt2,
                       int numdims)
{
    float ans = 0.0f;
    for (int i = 0; i < numdims; i++) {
        float diff = pt1[i] - pt2[i];
        ans += diff * diff;
    }
    return ans;
}

int find_nearest_point_cl(const float *pt,
                          int nfeatures,
                          const float *clusters,
                          int nclusters,
                          int nfeatures_per_cluster)
{
    int index = 0;
    float min_dist = FLT_MAX;

    for (int i = 0; i < nclusters; i++) {
        float dist = euclid_dist_2_cl(pt, clusters + (i * nfeatures_per_cluster), nfeatures);
        if (dist < min_dist) {
            min_dist = dist;
            index = i;
        }
    }
    return index;
}

void kmeans_clustering_kernel(const float *feature,
                              int nfeatures,
                              int npoints,
                              int nclusters,
                              float threshold,
                              int *membership,
                              float *clusters,
                              int *new_centers_len,
                              float *new_centers,
                              int *partial_new_centers_len,
                              float *partial_new_centers,
                              int nthreads,
                              int tid,
                              int start_idx,
                              int end_idx,
                              float *delta_out)
{
    float delta = 0.0f;

    for (int i = start_idx; i < end_idx; i++) {
        int index = find_nearest_point_cl(feature + (i * nfeatures),
                                          nfeatures,
                                          clusters,
                                          nclusters,
                                          nfeatures);

        if (index != membership[i]) {
            delta += 1.0f;
        }

        membership[i] = index;

        partial_new_centers_len[tid * nclusters + index]++;

        for (int j = 0; j < nfeatures; j++) {
            partial_new_centers[(tid * nclusters + index) * nfeatures + j] += feature[i * nfeatures + j];
        }
    }

    *delta_out = delta;
}

void aggregate_centers_kernel(float *new_centers_len,
                              float *new_centers,
                              int *partial_new_centers_len,
                              float *partial_new_centers,
                              int nclusters,
                              int nthreads,
                              int nfeatures)
{
    for (int i = 0; i < nclusters; i++) {
        float count = 0.0f;
        for (int j = 0; j < nthreads; j++) {
            count += partial_new_centers_len[j * nclusters + i];
            partial_new_centers_len[j * nclusters + i] = 0;

            for (int k = 0; k < nfeatures; k++) {
                new_centers[i * nfeatures + k] += partial_new_centers[(j * nclusters + i) * nfeatures + k];
                partial_new_centers[(j * nclusters + i) * nfeatures + k] = 0.0f;
            }
        }
        new_centers_len[i] = count;
    }
}

void update_centers_kernel(float *clusters,
                           float *new_centers,
                           float *new_centers_len,
                           int nclusters,
                           int nfeatures)
{
    for (int i = 0; i < nclusters; i++) {
        if (new_centers_len[i] > 0.0f) {
            for (int j = 0; j < nfeatures; j++) {
                clusters[i * nfeatures + j] = new_centers[i * nfeatures + j] / new_centers_len[i];
                new_centers[i * nfeatures + j] = 0.0f;
            }
        } else {
            for (int j = 0; j < nfeatures; j++) {
                new_centers[i * nfeatures + j] = 0.0f;
            }
        }
        new_centers_len[i] = 0.0f;
    }
}
